import React, { useState } from "react";

function Contact() {
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    message: ""
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    alert(`Thank you, ${formData.name}! Your message has been received.`);
    setFormData({ name: "", email: "", message: "" });
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Contact Us</h2>
      <p><strong>Office:</strong> 5 Elephant Close, Borrowdale West, Harare</p>
      <p><strong>Phone:</strong> +263 785 002 561</p>
      <p><strong>Email:</strong> pnovontony@yahoo.com</p>

      <form
        action="https://formspree.io/f/xwvnjkgl"
        method="POST"
        style={{ marginTop: "20px" }}
      >
        <div style={{ marginBottom: "10px" }}>
          <label>Name:</label><br />
          <input type="text" name="name" required style={{ width: "100%", padding: "8px" }} />
        </div>
        <div style={{ marginBottom: "10px" }}>
          <label>Email:</label><br />
          <input type="email" name="email" required style={{ width: "100%", padding: "8px" }} />
        </div>
        <div style={{ marginBottom: "10px" }}>
          <label>Message:</label><br />
          <textarea name="message" required rows="4" style={{ width: "100%", padding: "8px" }} />
        </div>
        <button type="submit" style={{ padding: "10px 20px" }}>
          Send Message
        </button>
      </form>
    </div>
  );
}

export default Contact;
